{"command": "python -c "
import codecs
try:
    codecs.encode('→', 'cp1252')
except UnicodeEncodeError as e:
    print('Default error handler raises:', e)

# Test different error handlers
print('\\nTesting error handlers:')
for errors in ['strict', 'replace', 'ignore', 'backslashreplace', 'xmlcharrefreplace', 'namereplace']:
    try:
        result = codecs.encode('→', 'cp1252', errors=errors)
        print(f'{errors}: {result}')
    except Exception as e:
        print(f'{errors}: {e}')
""}

